// // This module implements a 3-to-1 multiplexer with a 2-bit select input, choosing between register, memory, and immediate values. The output defaults to the value from the register when opsource is 00.
module top_module(opsource, rg, mem, imm, out);input [1:0] opsource;
	input [15:0] rg, mem, imm;
	output reg [15:0] out;

	always@(opsource or rg or mem or imm)
		begin
			case(opsource)

				2'B00: out = rg;
				2'B01: out = mem;
				2'B10: out = imm;
				default: out = 0;

			endcase
		end

endmodule
